function doGet(e) {
  var fileId = e.parameter.id;
  if (!fileId) return ContentService.createTextOutput("Error: Falta ID").setMimeType(ContentService.MimeType.TEXT);

  // 1. Check Google's Server RAM
  var cache = CacheService.getScriptCache();
  var cachedContent = cache.get(fileId);

  if (cachedContent != null) {
    return ContentService.createTextOutput(cachedContent).setMimeType(ContentService.MimeType.TEXT);
  }

  // 2. Fetch from Drive (if not in RAM)
  try {
    var file = DriveApp.getFileById(fileId);
    var content = file.getBlob().getDataAsString();

    // Save to RAM for 1 hour (3600 seconds)
    if (content.length < 100000) {
      cache.put(fileId, content, 3600); 
    }

    return ContentService.createTextOutput(content).setMimeType(ContentService.MimeType.TEXT);
  } catch (err) {
    return ContentService.createTextOutput("Error al leer el archivo de Drive.").setMimeType(ContentService.MimeType.TEXT);
  }
}
